1	{
2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
3	  "$id": "https://yoke.local/schemas/handoff.schema.json",
4	  "title": "handoff.json",
5	  "description": "Per-item, append-only structured cross-phase channel (plan-draft3 §File Contract, D13). Replaces free-form progress.md as the contract surface between phases. User-injected context from the dashboard lands here as entries.user_injected_context (D43). The harness writes entries; agents read. Item ID matches whatever the stage's items_id expression extracts (Issue 2).",
6	  "type": "object",
7	  "additionalProperties": false,
8	  "required": ["item_id", "entries"],
9	  "properties": {
10	    "item_id": {
11	      "type": "string",
12	      "minLength": 1,
13	      "description": "Item identifier as extracted by the stage's items_id expression. No pattern enforced by the harness (Issue 2)."
14	    },
15	    "entries": {
16	      "type": "array",
17	      "items": { "$ref": "#/$defs/entry" }
18	    }
19	  },
20	  "$defs": {
21	    "entry": {
22	      "type": "object",
23	      "additionalProperties": false,
24	      "required": ["phase", "attempt", "session_id", "ts"],
25	      "properties": {
26	        "phase": {
27	          "type": "string",
28	          "description": "Free-text phase label (not an enum)."
29	        },
30	        "attempt": {
31	          "type": "integer",
32	          "minimum": 1
33	        },
34	        "session_id": { "type": "string" },
35	        "parent_session_id": {
36	          "type": ["string", "null"],
37	          "description": "Session chain link for -c continuation (plan-draft3 §Protocol: token usage)."
38	        },
39	        "ts": { "type": "string", "format": "date-time" },
40	        "intended_files": {
41	          "type": "array",
42	          "items": { "type": "string" },
43	          "description": "Files the implementer intended to modify. Used by reviewers to detect incidental churn."
44	        },
45	        "deferred_criteria": {
46	          "type": "array",
47	          "items": { "type": "string" },
48	          "description": "Acceptance criteria the implementer consciously deferred with a reason."
49	        },
50	        "known_risks": {
51	          "type": "array",
52	          "items": { "type": "string" }
53	        },
54	        "retry_history": {
55	          "type": "array",
56	          "items": { "$ref": "#/$defs/retryRecord" }
57	        },
58	        "reviewer_notes_seen": {
59	          "type": "array",
60	          "items": { "type": "string" },
61	          "description": "Reviewer note identifiers the implementer has explicitly read (seeded from prior review rounds)."
62	        },
63	        "user_injected_context": {
64	          "oneOf": [
65	            { "type": "null" },
66	            { "$ref": "#/$defs/injection" }
67	          ],
68	          "description": "Set by the dashboard when the user injects context for the next session of this feature (D43). Consumed on the next session start."
69	        },
70	        "failure_summary": {
71	          "type": ["string", "null"],
72	          "description": "Written by the harness when escalating to retry_mode=fresh_with_failure_summary (plan-draft3 §Retry)."
73	        }
74	      }
75	    },
76	    "retryRecord": {
77	      "type": "object",
78	      "additionalProperties": false,
79	      "required": ["attempt", "mode", "outcome", "ts"],
80	      "properties": {
81	        "attempt": { "type": "integer", "minimum": 1 },
82	        "mode": {
83	          "type": "string",
84	          "enum": ["continue", "fresh_with_failure_summary", "fresh_with_diff"]
85	        },
86	        "outcome": {
87	          "type": "string",
88	          "enum": ["ok", "fail", "rate_limited", "crash", "awaiting_user"]
89	        },
90	        "classifier": {
91	          "type": "string",
92	          "enum": ["transient", "permanent", "policy", "unknown"]
93	        },
94	        "ts": { "type": "string", "format": "date-time" }
95	      }
96	    },
97	    "injection": {
98	      "type": "object",
99	      "additionalProperties": false,
100	      "required": ["text", "queued_at", "queued_by"],
101	      "properties": {
102	        "text": { "type": "string", "minLength": 1 },
103	        "queued_at": { "type": "string", "format": "date-time" },
104	        "queued_by": {
105	          "type": "string",
106	          "description": "Always the single local user (plan-draft3 D57); present for audit only."
107	        },
108	        "consumed_at": {
109	          "type": ["string", "null"],
110	          "format": "date-time"
111	        },
112	        "consumed_by_session_id": { "type": ["string", "null"] }
113	      }
114	    }
115	  }
116	}
