1	{
2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
3	  "$id": "https://yoke.local/schemas/review.schema.json",
4	  "title": "reviews/<item-id>/<angle>.json (recommended template)",
5	  "description": "Recommended schema for one reviewer subagent's verdict for one item in the default workflow. This is NOT a harness contract — the harness does not read or parse review files (Issue 4). Pass/fail is determined by the review phase's post: commands, not by harness-level aggregation. The default workflow ships a post command that reads these files and checks verdicts. Users with different review models may define their own schema or skip review entirely.",
6	  "type": "object",
7	  "additionalProperties": false,
8	  "required": [
9	    "item_id",
10	    "reviewer",
11	    "reviewed_commit",
12	    "verdict",
13	    "acceptance_criteria_verdicts",
14	    "review_criteria_verdicts"
15	  ],
16	  "properties": {
17	    "item_id": {
18	      "type": "string",
19	      "minLength": 1,
20	      "description": "The item identifier as extracted by the stage's items_id expression. No pattern enforced (Issue 2)."
21	    },
22	    "reviewer": {
23	      "type": "string",
24	      "minLength": 1,
25	      "description": "Reviewer angle label (e.g. security, complexity, best-practices). Must match the <angle>.json file name."
26	    },
27	    "reviewed_commit": {
28	      "type": "string",
29	      "pattern": "^[0-9a-f]{7,40}$"
30	    },
31	    "verdict": {
32	      "type": "string",
33	      "enum": ["pass", "fail"]
34	    },
35	    "acceptance_criteria_verdicts": {
36	      "type": "array",
37	      "minItems": 1,
38	      "items": { "$ref": "#/$defs/criterionVerdict" }
39	    },
40	    "review_criteria_verdicts": {
41	      "type": "array",
42	      "minItems": 1,
43	      "items": { "$ref": "#/$defs/criterionVerdict" }
44	    },
45	    "additional_issues": {
46	      "type": "array",
47	      "items": { "$ref": "#/$defs/additionalIssue" }
48	    },
49	    "notes": {
50	      "type": "string",
51	      "description": "Optional free-form summary; not interpreted by the aggregator."
52	    }
53	  },
54	  "$defs": {
55	    "criterionVerdict": {
56	      "type": "object",
57	      "additionalProperties": false,
58	      "required": ["criterion", "pass"],
59	      "properties": {
60	        "criterion": {
61	          "type": "string",
62	          "minLength": 1
63	        },
64	        "pass": { "type": "boolean" },
65	        "notes": { "type": "string" }
66	      }
67	    },
68	    "additionalIssue": {
69	      "type": "object",
70	      "additionalProperties": false,
71	      "required": ["severity", "category", "description"],
72	      "properties": {
73	        "severity": {
74	          "type": "string",
75	          "enum": ["info", "low", "medium", "high", "critical"]
76	        },
77	        "category": {
78	          "type": "string",
79	          "description": "Free-text angle label (e.g. security, perf, style)."
80	        },
81	        "description": { "type": "string", "minLength": 1 },
82	        "file": { "type": "string" },
83	        "line": { "type": "integer", "minimum": 1 },
84	        "suggestion": { "type": "string" }
85	      }
86	    }
87	  }
88	}
