2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
3	  "$id": "https://yoke.local/schemas/yoke-config.schema.json",
4	  "title": ".yoke.yml",
5	  "description": "User-authored configuration. Mirrors plan-draft3 §Configuration and the pre/post action grammar (§Phase Pre/Post Commands, D50, D53). Revised per beta3-review-feedback.md Issues 1–4: pipeline uses stages (not nodes+edges), items are opaque, review aggregation is user-owned. All object schemas set additionalProperties: false to fail fast on typos.",
6	  "type": "object",
7	  "additionalProperties": false,
8	  "required": ["version", "project", "pipeline", "phases"],
9	  "properties": {
10	    "version": {
11	      "type": "string",
12	      "const": "1",
13	      "description": "Schema version pin. Must be a quoted string '1' so YAML parsers don't coerce 1.10 → 1.1."
14	    },
15	    "project": {
16	      "type": "object",
17	      "additionalProperties": false,
18	      "required": ["name"],
19	      "properties": {
20	        "name": { "type": "string", "minLength": 1 }
21	      }
22	    },
23	    "pipeline": { "$ref": "#/$defs/pipeline" },
24	    "phases": {
25	      "type": "object",
26	      "minProperties": 1,
27	      "additionalProperties": { "$ref": "#/$defs/phase" }
28	    },
29	    "worktrees": { "$ref": "#/$defs/worktrees" },
30	    "notifications": { "$ref": "#/$defs/notifications" },
31	    "github": { "$ref": "#/$defs/github" },
32	    "retention": { "$ref": "#/$defs/retention" },
33	    "logging": { "$ref": "#/$defs/logging" },
34	    "runtime": { "$ref": "#/$defs/runtime" },
35	    "rate_limit": { "$ref": "#/$defs/rateLimit" },
36	    "ui": { "$ref": "#/$defs/ui" },
37	    "safety_mode": {
38	      "type": "string",
39	      "enum": ["strict", "default", "yolo"],
40	      "default": "default",
41	      "description": "Parameterizes the example safety hook template offered by yoke init. Advisory, not runtime-enforced (plan-draft3 §Threat Model, D51)."
42	    }
43	  },
44	
45	  "$defs": {
46	
47	    "pipeline": {
48	      "type": "object",
49	      "additionalProperties": false,
50	      "required": ["stages"],
51	      "description": "Pipeline structure using stages (Issue 1). Stage-to-stage flow is always sequential. Within a per-item stage, phase-to-phase transitions use the post: action grammar.",
52	      "properties": {
53	        "stages": {
54	          "type": "array",
55	          "minItems": 1,
56	          "items": { "$ref": "#/$defs/stage" }
57	        }
58	      }
59	    },
60	
61	    "stage": {
62	      "type": "object",
63	      "additionalProperties": false,
64	      "required": ["id", "run", "phases"],
65	      "description": "A stage groups an ordered sequence of phases and declares whether they run once (per workflow) or per-item (per item in a manifest). Issue 1.",
66	      "properties": {
67	        "id": {
68	          "type": "string",
69	          "minLength": 1,
70	          "description": "Stable stage identifier. Unique within the pipeline."
71	        },
72	        "run": {
73	          "type": "string",
74	          "enum": ["once", "per-item"],
75	          "description": "once: phases run once for the workflow. per-item: phases run once per item from the manifest file (Issue 1)."
76	        },
77	        "phases": {
78	          "type": "array",
79	          "minItems": 1,
80	          "items": { "type": "string" },
81	          "description": "Ordered list of phase keys (references into the top-level phases map). Within a per-item stage, the post: action grammar applies to phase-to-phase transitions for the same item (Issue 1)."
82	        },
83	        "needs_approval": {
84	          "type": "boolean",
85	          "default": false,
86	          "description": "When true, the harness enters awaiting_user before starting this stage, requiring explicit user approval to proceed. Replaces the former edge-level needs_approval (Q-architecture-proposed-lifecycle)."
87	        },
88	        "items_from": {
89	          "type": "string",
90	          "description": "Path to the item manifest file, relative to the worktree. Required for per-item stages (Issue 2)."
91	        },
92	        "items_list": {
93	          "type": "string",
94	          "description": "JSONPath expression evaluated against items_from to extract the item array (Issue 2). E.g. '$.features'."
95	        },
96	        "items_id": {
97	          "type": "string",
98	          "description": "JSONPath expression evaluated per item to extract a stable string identifier (Issue 2). E.g. '$.id'."
99	        },
100	        "items_depends_on": {
101	          "type": "string",
102	          "description": "Optional JSONPath expression evaluated per item to extract an array of dependency item IDs for topological ordering (D08). If omitted, items are processed in manifest order with no dependency constraints."
103	        },
104	        "items_display": { "$ref": "#/$defs/itemsDisplay" }
105	      },
106	      "allOf": [
107	        {
108	          "if": { "properties": { "run": { "const": "per-item" } }, "required": ["run"] },
109	          "then": { "required": ["items_from", "items_list", "items_id"] }
110	        }
111	      ]
112	    },
113	
114	    "itemsDisplay": {
115	      "type": "object",
116	      "additionalProperties": false,
117	      "description": "Dashboard rendering hints for items (Issue 2). If omitted, the dashboard shows the raw item ID.",
118	      "properties": {
119	        "title": {
120	          "type": "string",
121	          "description": "JSONPath expression per item for the dashboard row label."
122	        },
123	        "subtitle": {
124	          "type": "string",
125	          "description": "Optional JSONPath expression per item for secondary dashboard text."
126	        }
127	      }
128	    },
129	
130	    "phase": {
131	      "type": "object",
132	      "additionalProperties": false,
133	      "required": ["command", "args", "prompt_template"],
134	      "properties": {
135	        "command": {
136	          "type": "string",
137	          "description": "Command to spawn. Default in docs is 'claude'; jig is one documented alternative but not required (D55)."
138	        },
139	        "args": {
140	          "type": "array",
141	          "items": { "type": "string" }
142	        },
143	        "env": {
144	          "type": "object",
145	          "additionalProperties": { "type": "string" }
146	        },
147	        "cwd": {
148	          "type": "string",
149	          "description": "Optional override; defaults to the worktree path."
150	        },
151	        "prompt_template": { "type": "string" },
152	        "output_artifacts": {
153	          "type": "array",
154	          "items": { "$ref": "#/$defs/outputArtifact" }
155	        },
156	        "max_outer_retries": {
157	          "type": "integer",
158	          "minimum": 0,
159	          "default": 2
160	        },
161	        "retry_ladder": {
162	          "type": "array",
163	          "items": {
164	            "type": "string",
165	            "enum": [
166	              "continue",
167	              "fresh_with_failure_summary",
168	              "fresh_with_diff",
169	              "awaiting_user"
170	            ]
171	          }
172	        },
173	        "heartbeat": { "$ref": "#/$defs/heartbeat" },
174	        "pre": {
175	          "type": "array",
176	          "items": { "$ref": "#/$defs/prepostCommand" }
177	        },
178	        "post": {
179	          "type": "array",
180	          "items": { "$ref": "#/$defs/prepostCommand" }
181	        }
182	      }
183	    },
184	
185	    "outputArtifact": {
186	      "type": "object",
187	      "additionalProperties": false,
188	      "required": ["path"],
189	      "properties": {
190	        "path": { "type": "string" },
191	        "schema": { "type": "string", "description": "Relative path to a JSON schema file." },
192	        "required": { "type": "boolean", "default": true }
193	      }
194	    },
195	
196	    "heartbeat": {
197	      "type": "object",
198	      "additionalProperties": false,
199	      "properties": {
200	        "activity_timeout_s": { "type": "integer", "minimum": 1, "default": 90 },
201	        "per_tool_budgets": {
202	          "type": "object",
203	          "additionalProperties": { "type": "integer", "minimum": 1 },
204	          "description": "Tool-name → wall-clock budget in seconds; used for liveness signal only (plan-draft3 §Heartbeat, D23)."
205	        }
206	      }
207	    },
208	
209	    "prepostCommand": {
210	      "type": "object",
211	      "additionalProperties": false,
212	      "required": ["name", "run", "actions"],
213	      "properties": {
214	        "name": { "type": "string", "minLength": 1 },
215	        "run": {
216	          "type": "array",
217	          "minItems": 1,
218	          "items": { "type": "string" },
219	          "description": "argv-form command. Spawned with shell: false."
220	        },
221	        "timeout_s": {
222	          "type": "integer",
223	          "minimum": 1,
224	          "default": 900
225	        },
226	        "env": {
227	          "type": "object",
228	          "additionalProperties": { "type": "string" }
229	        },
230	        "actions": { "$ref": "#/$defs/actionsMap" }
231	      }
232	    },
233	
234	    "actionsMap": {
235	      "type": "object",
236	      "minProperties": 1,
237	      "propertyNames": {
238	        "pattern": "^([0-9]+|\\*)$"
239	      },
240	      "additionalProperties": { "$ref": "#/$defs/action" },
241	      "description": "Exit-code → action. Key is an integer exit code or '*' wildcard. See schemas/pre-post-action-grammar.md for the normative grammar."
242	    },
243	
244	    "action": {
245	      "oneOf": [
246	        {
247	          "type": "string",
248	          "enum": ["continue", "stop-and-ask", "stop"]
249	        },
250	        {
251	          "type": "object",
252	          "additionalProperties": false,
253	          "required": ["goto"],
254	          "properties": {
255	            "goto": { "type": "string" },
256	            "max_revisits": { "type": "integer", "minimum": 1, "default": 3 }
257	          }
258	        },
259	        {
260	          "type": "object",
261	          "additionalProperties": false,
262	          "required": ["retry"],
263	          "properties": {
264	            "retry": {
265	              "type": "object",
266	              "additionalProperties": false,
267	              "required": ["mode", "max"],
268	              "properties": {
269	                "mode": {
270	                  "type": "string",
271	                  "enum": [
272	                    "continue",
273	                    "fresh_with_failure_summary",
274	                    "fresh_with_diff"
275	                  ]
276	                },
277	                "max": { "type": "integer", "minimum": 1 }
278	              }
279	            }
280	          }
281	        },
282	        {
283	          "type": "object",
284	          "additionalProperties": false,
285	          "required": ["fail"],
286	          "properties": {
287	            "fail": {
288	              "type": "object",
289	              "additionalProperties": false,
290	              "required": ["reason"],
291	              "properties": {
292	                "reason": { "type": "string", "minLength": 1 }
293	              }
294	            }
295	          }
296	        }
297	      ]
298	    },
299	
300	    "worktrees": {
301	      "type": "object",
302	      "additionalProperties": false,
303	      "properties": {
304	        "base_dir": { "type": "string", "default": ".worktrees" },
305	        "branch_prefix": { "type": "string", "default": "yoke/" },
306	        "auto_cleanup": { "type": "boolean", "default": true },
307	        "cleanup_tool": {
308	          "type": "string",
309	          "enum": ["git", "lazyworktree", "custom"],
310	          "default": "git"
311	        },
312	        "bootstrap": {
313	          "type": "object",
314	          "additionalProperties": false,
315	          "properties": {
316	            "commands": { "type": "array", "items": { "type": "string" } }
317	          }
318	        },
319	        "teardown": {
320	          "type": "object",
321	          "additionalProperties": false,
322	          "properties": {
323	            "script": { "type": "string" }
324	          }
325	        }
326	      }
327	    },
328	
329	    "notifications": {
330	      "type": "object",
331	      "additionalProperties": false,
332	      "properties": {
333	        "enabled": { "type": "boolean", "default": true },
334	        "severity_map": {
335	          "type": "object",
336	          "additionalProperties": {
337	            "type": "string",
338	            "enum": ["info", "requires_attention"]
339	          }
340	        },
341	        "mechanisms": {
342	          "type": "array",
343	          "items": {
344	            "type": "object",
345	            "additionalProperties": false,
346	            "required": ["type"],
347	            "properties": {
348	              "type": {
349	                "type": "string",
350	                "enum": ["browser_push", "macos_native"]
351	              }
352	            }
353	          }
354	        }
355	      }
356	    },
357	
358	    "github": {
359	      "type": "object",
360	      "additionalProperties": false,
361	      "properties": {
362	        "enabled": { "type": "boolean", "default": false },
363	        "auto_pr": { "type": "boolean", "default": true },
364	        "pr_target_branch": { "type": "string", "default": "main" },
365	        "auth_order": {
366	          "type": "array",
367	          "items": {
368	            "type": "string",
369	            "enum": ["env:GITHUB_TOKEN", "gh:auth:token"]
370	          }
371	        },
372	        "attach_artifacts_to_pr": { "type": "boolean", "default": false },
373	        "link_issues": { "type": "boolean", "default": false }
374	      }
375	    },
376	
377	    "retention": {
378	      "type": "object",
379	      "additionalProperties": false,
380	      "properties": {
381	        "sqlite": {
382	          "oneOf": [
383	            { "type": "string", "enum": ["forever"] },
384	            { "type": "object",
385	              "additionalProperties": false,
386	              "properties": {
387	                "max_age_days": { "type": "integer", "minimum": 1 }
388	              }
389	            }
390	          ]
391	        },
392	        "stream_json_logs": {
393	          "type": "object",
394	          "additionalProperties": false,
395	          "properties": {
396	            "max_age_days": { "type": "integer", "minimum": 1, "default": 30 },
397	            "max_total_bytes": { "type": "integer", "minimum": 1 }
398	          }
399	        },
400	        "worktrees": {
401	          "type": "string",
402	          "enum": ["workflow-completion", "manual", "on-disk-pressure"],
403	          "default": "workflow-completion"
404	        }
405	      }
406	    },
407	
408	    "logging": {
409	      "type": "object",
410	      "additionalProperties": false,
411	      "description": "Database and session log paths are derived from ~/.yoke/<fingerprint>/ and are not user-configurable (Q-session-log-directory-collisions resolution).",
412	      "properties": {
413	        "retain_stream_json": { "type": "boolean", "default": true }
414	      }
415	    },
416	
417	    "runtime": {
418	      "type": "object",
419	      "additionalProperties": false,
420	      "properties": {
421	        "keep_awake": {
422	          "type": "boolean",
423	          "default": false,
424	          "description": "D60: when true, the harness spawns caffeinate -i (macOS) or systemd-inhibit (Linux) as a workflow-lifetime child. Windows deferred to v1.1."
425	        }
426	      }
427	    },
428	
429	    "rateLimit": {
430	      "type": "object",
